using System;
using System.Text.Json;

namespace AvatarBuilder.Modules.Vision.MediaPipe.Reconstruction;

public static class MediaPipeNormalizedFaceViewerPage
{
	private static readonly JsonSerializerOptions JsonOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

	public static string Build(MediaPipeNormalizedFaceModel model)
	{
		ArgumentNullException.ThrowIfNull(model, "model");
		// This restored viewer expects its original edge names; keep the shared topology model unchanged.
		string text = JsonSerializer.Serialize(model, JsonOptions)
			.Replace("\"fromIndex\":", "\"startIndex\":", StringComparison.Ordinal)
			.Replace("\"toIndex\":", "\"endIndex\":", StringComparison.Ordinal)
			.Replace("</", "<\\/", StringComparison.Ordinal);
		return "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>MediaPipe Measured Face Geometry</title>\n  <style>\n    :root { color-scheme: dark; font-family: \"Segoe UI\", Arial, sans-serif; background:#061019; color:#e7f4ff; }\n    * { box-sizing:border-box; }\n    body { margin:0; min-height:100vh; background:#061019; }\n    header { height:54px; display:flex; align-items:center; gap:8px; padding:8px 12px; border-bottom:1px solid #254052; background:#0a1721; }\n    button { color:#e7f4ff; background:#10283a; border:1px solid #397397; padding:8px 12px; cursor:pointer; }\n    button[aria-pressed=\"true\"] { background:#15567a; border-color:#63c9ff; }\n    .spacer { flex:1; }\n    .layout { height:calc(100vh - 54px); display:grid; grid-template-columns:minmax(0,1fr) 330px; }\n    .stage { position:relative; min-width:0; overflow:hidden; }\n    canvas { width:100%; height:100%; display:block; background:#040b11; touch-action:none; }\n    .hint { position:absolute; left:14px; top:12px; padding:8px 10px; background:#07121dcc; border:1px solid #20394b; color:#b9d7ef; font-size:12px; pointer-events:none; }\n    aside { overflow:auto; padding:16px; border-left:1px solid #254052; background:#08141d; }\n    h1 { margin:0 0 4px; font-size:20px; letter-spacing:0; }\n    h2 { margin:20px 0 8px; font-size:13px; color:#80e0a4; letter-spacing:0; }\n    p { margin:5px 0; line-height:1.4; }\n    .muted { color:#9ebdd2; font-size:12px; }\n    .status { color:#ffd27a; }\n    .metric { display:grid; grid-template-columns:1fr auto; gap:10px; padding:7px 0; border-bottom:1px solid #193044; font-size:12px; }\n    .metric strong { color:#dff5ff; font-variant-numeric:tabular-nums; }\n    .legend { display:grid; gap:7px; font-size:12px; }\n    .swatch { display:inline-block; width:18px; height:2px; margin-right:8px; vertical-align:middle; }\n    .warning { margin-top:16px; padding:10px; border:1px solid #755d26; color:#ffd27a; background:#1b1609; font-size:12px; line-height:1.4; }\n    @media (max-width:800px) { .layout { grid-template-columns:1fr; grid-template-rows:minmax(420px,65vh) auto; height:auto; } aside { border-left:0; border-top:1px solid #254052; } }\n  </style>\n</head>\n<body>\n  <header>\n    <button id=\"points\" aria-pressed=\"true\">Points</button>\n    <button id=\"wire\" aria-pressed=\"true\">Wireframe</button>\n    <button id=\"hull\" aria-pressed=\"true\">Silhouette Hull</button>\n    <button id=\"reset\">Reset 3D View</button>\n    <span class=\"spacer\"></span>\n    <button id=\"updates\" aria-pressed=\"true\">Live Updates</button>\n    <button id=\"refresh\">Refresh Now</button>\n  </header>\n  <main class=\"layout\">\n    <section class=\"stage\">\n      <canvas id=\"view\"></canvas>\n      <div class=\"hint\">Drag to rotate; wheel to zoom. Only directly observed evidence is bright.</div>\n    </section>\n    <aside>\n      <h1>Measured Face Geometry</h1>\n      <p><strong id=\"subject\"></strong></p>\n      <p class=\"muted\" id=\"updated\"></p>\n      <p class=\"status\" id=\"status\"></p>\n      <h2>Evidence</h2>\n      <div id=\"metrics\"></div>\n      <h2>Display Key</h2>\n      <div class=\"legend\">\n        <div><span class=\"swatch\" style=\"background:#62d5ff\"></span>Directly measured</div>\n        <div><span class=\"swatch\" style=\"background:#ffd166\"></span>Partially measured or expression point</div>\n        <div><span class=\"swatch\" style=\"background:#405869\"></span>Underconstrained</div>\n        <div><span class=\"swatch\" style=\"background:#7ff0bd\"></span>Angle-binned silhouette hull</div>\n      </div>\n      <div class=\"warning\">This view separates observed constraints from underconstrained geometry. It is a measurement and reconstruction aid, not proof that hidden or uncovered surfaces have been measured.</div>\n    </aside>\n  </main>\n  <script>\n    const model = " + text + ";\n    const canvas = document.getElementById('view');\n    const ctx = canvas.getContext('2d', { alpha:false });\n    const stateKey = 'avatarBuilder.mediaPipeGeometryView';\n    let saved = {};\n    try { saved = JSON.parse(localStorage.getItem(stateKey) || '{}'); } catch { }\n    const view = {\n      yaw: Number.isFinite(saved.yaw) ? saved.yaw : -0.25,\n      pitch: Number.isFinite(saved.pitch) ? saved.pitch : 0.04,\n      zoom: Number.isFinite(saved.zoom) ? saved.zoom : 0.82,\n      points: saved.points !== false,\n      wire: saved.wire !== false,\n      hull: saved.hull !== false,\n      updates: saved.updates !== false\n    };\n    let dragging = false, lastX = 0, lastY = 0;\n\n    function saveView() { localStorage.setItem(stateKey, JSON.stringify(view)); }\n    function finite(v) { return Number.isFinite(v) ? v : 0; }\n    function fmt(v, digits=1) { return finite(v).toFixed(digits); }\n    function range(a,b) { return Math.max(0, finite(b)-finite(a)); }\n    function setPressed(id, value) { document.getElementById(id).setAttribute('aria-pressed', value ? 'true' : 'false'); }\n    function metric(label, value) { return `<div class=\"metric\"><span>${label}</span><strong>${value}</strong></div>`; }\n\n    document.getElementById('subject').textContent = model.subjectDisplayName || model.subjectId || 'No profile';\n    document.getElementById('updated').textContent = model.updatedAtUtc ? `Updated ${new Date(model.updatedAtUtc).toLocaleString()}` : 'Waiting for the first accepted frame';\n    document.getElementById('status').textContent = model.status || '';\n    document.getElementById('metrics').innerHTML =\n      metric('Accepted frames', Number(model.acceptedFrameCount || 0).toLocaleString()) +\n      metric('Rejected frames', Number(model.rejectedFrameCount || 0).toLocaleString()) +\n      metric('Direct observations', Number(model.directLandmarkObservationCount || 0).toLocaleString()) +\n      metric('Hidden predictions discarded', Number(model.hiddenLandmarkRejectionCount || 0).toLocaleString()) +\n      metric('Directly constrained vertices', `${fmt(model.confidentVertexPercent)}%`) +\n      metric('Median reprojection residual', `${fmt(model.medianResidualPercent,2)}%`) +\n      metric('A coverage', `${fmt(range(model.minimumARotationDegrees, model.maximumARotationDegrees))} deg`) +\n      metric('B coverage', `${fmt(range(model.minimumBRotationDegrees, model.maximumBRotationDegrees))} deg`) +\n      metric('C coverage', `${fmt(range(model.minimumCRotationDegrees, model.maximumCRotationDegrees))} deg`) +\n      metric('Silhouette angle profiles', Number((model.silhouetteProfiles || []).length).toLocaleString()) +\n      metric('Visual-hull slices', Number((model.visualHullSlices || []).length).toLocaleString());\n\n    function resize() {\n      const dpr = Math.min(2, window.devicePixelRatio || 1);\n      const rect = canvas.getBoundingClientRect();\n      canvas.width = Math.max(1, Math.round(rect.width*dpr));\n      canvas.height = Math.max(1, Math.round(rect.height*dpr));\n      ctx.setTransform(dpr,0,0,dpr,0,0);\n      draw();\n    }\n\n    function rotate(p) {\n      const cy=Math.cos(view.yaw), sy=Math.sin(view.yaw), cp=Math.cos(view.pitch), sp=Math.sin(view.pitch);\n      const x1=cy*p.x + sy*p.z, z1=-sy*p.x + cy*p.z;\n      return { x:x1, y:cp*p.y-sp*z1, z:sp*p.y+cp*z1 };\n    }\n\n    function evidenceColor(v, alpha=1) {\n      if (v.evidenceClass === 'directly-measured') return `rgba(98,213,255,${alpha})`;\n      if (v.evidenceClass === 'partially-measured' || v.evidenceClass === 'expression-only') return `rgba(255,209,102,${alpha})`;\n      return `rgba(64,88,105,${alpha})`;\n    }\n\n    function draw() {\n      const w=canvas.clientWidth, h=canvas.clientHeight;\n      ctx.fillStyle='#040b11'; ctx.fillRect(0,0,w,h);\n      const vertices=(model.vertices || []).map(v => ({...v, r:rotate({x:finite(v.x),y:finite(v.y),z:finite(v.z)})}));\n      const usable=vertices.filter(v => Number(v.directObservationCount || 0)>0);\n      if (!usable.length) {\n        ctx.fillStyle='#9ebdd2'; ctx.font='16px Segoe UI'; ctx.textAlign='center';\n        ctx.fillText('Start MediaPipe Geometry Capture and turn slowly left and right.', w/2, h/2);\n        return;\n      }\n      let minX=Infinity,maxX=-Infinity,minY=Infinity,maxY=-Infinity;\n      for (const v of usable) { minX=Math.min(minX,v.r.x); maxX=Math.max(maxX,v.r.x); minY=Math.min(minY,v.r.y); maxY=Math.max(maxY,v.r.y); }\n      const span=Math.max(0.2,maxX-minX,maxY-minY);\n      const scale=Math.min(w,h)*view.zoom/span;\n      const centerX=(minX+maxX)/2, centerY=(minY+maxY)/2;\n      const project = r => ({ x:w/2+(r.x-centerX)*scale, y:h/2-(r.y-centerY)*scale, z:r.z });\n      const projected=vertices.map(v => ({...v, p:project(v.r)}));\n\n      if (view.hull) {\n        ctx.strokeStyle='rgba(127,240,189,.55)'; ctx.lineWidth=1;\n        for (const slice of model.visualHullSlices || []) {\n          if (!slice.boundary || slice.boundary.length<3) continue;\n          const ring=slice.boundary.map(q => project(rotate({x:finite(q.x),y:finite(slice.canonicalY),z:finite(q.z)})));\n          ctx.beginPath(); ctx.moveTo(ring[0].x,ring[0].y);\n          for(let i=1;i<ring.length;i++) ctx.lineTo(ring[i].x,ring[i].y);\n          ctx.closePath(); ctx.stroke();\n        }\n      }\n\n      if (view.wire) {\n        ctx.lineWidth=.65;\n        for (const edge of model.topologyEdges || []) {\n          const a=projected[edge.startIndex], b=projected[edge.endIndex];\n          if (!a || !b || (!a.directObservationCount && !b.directObservationCount)) continue;\n          const alpha=(a.evidenceClass==='underconstrained'||b.evidenceClass==='underconstrained') ? .18 : .52;\n          ctx.strokeStyle=evidenceColor(a,alpha); ctx.beginPath(); ctx.moveTo(a.p.x,a.p.y); ctx.lineTo(b.p.x,b.p.y); ctx.stroke();\n        }\n      }\n\n      if (view.points) {\n        projected.sort((a,b)=>a.p.z-b.p.z);\n        for (const v of projected) {\n          if (!v.directObservationCount) continue;\n          const radius=v.evidenceClass==='directly-measured' ? 1.25 : .9;\n          ctx.fillStyle=evidenceColor(v,.9); ctx.beginPath(); ctx.arc(v.p.x,v.p.y,radius,0,Math.PI*2); ctx.fill();\n        }\n      }\n    }\n\n    function toggle(id,key) { view[key]=!view[key]; setPressed(id,view[key]); saveView(); draw(); }\n    document.getElementById('points').onclick=()=>toggle('points','points');\n    document.getElementById('wire').onclick=()=>toggle('wire','wire');\n    document.getElementById('hull').onclick=()=>toggle('hull','hull');\n    document.getElementById('updates').onclick=()=>{ view.updates=!view.updates; setPressed('updates',view.updates); saveView(); };\n    document.getElementById('refresh').onclick=()=>location.reload();\n    document.getElementById('reset').onclick=()=>{ view.yaw=-.25; view.pitch=.04; view.zoom=.82; saveView(); draw(); };\n    setPressed('points',view.points); setPressed('wire',view.wire); setPressed('hull',view.hull); setPressed('updates',view.updates);\n\n    canvas.addEventListener('pointerdown',e=>{ dragging=true; lastX=e.clientX; lastY=e.clientY; canvas.setPointerCapture(e.pointerId); });\n    canvas.addEventListener('pointermove',e=>{ if(!dragging)return; view.yaw+=(e.clientX-lastX)*.008; view.pitch=Math.max(-1.45,Math.min(1.45,view.pitch+(e.clientY-lastY)*.008)); lastX=e.clientX;lastY=e.clientY;draw(); });\n    canvas.addEventListener('pointerup',()=>{ dragging=false; saveView(); });\n    canvas.addEventListener('wheel',e=>{ e.preventDefault(); view.zoom=Math.max(.18,Math.min(4,view.zoom*Math.exp(-e.deltaY*.001))); saveView(); draw(); },{passive:false});\n    new ResizeObserver(resize).observe(canvas);\n    setInterval(()=>{ if(view.updates && !dragging) location.reload(); },2500);\n  </script>\n</body>\n</html>";
	}
}
